import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"76. Vacancies","description":"","frontmatter":{"title":"76. Vacancies","eba":"Biomedical Engineers 2025-2028","topics":["consultation"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/76-vacancies.md","filePath":"ebas/biomedical-engineers/education-pd/76-vacancies.md"}'),s={name:"ebas/biomedical-engineers/education-pd/76-vacancies.md"};function i(r,e,c,l,h,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_76-vacancies" tabindex="-1">76. Vacancies <a class="header-anchor" href="#_76-vacancies" aria-label="Permalink to &quot;76. Vacancies&quot;">​</a></h1><p><strong>76.1</strong> This clause applies to a vacancy which relates to a position that, but for the vacancy occurring, would have been ongoing.</p><p><strong>76.2</strong> If the Employer elects to fill the vacancy, they will advertise the position as soon as reasonably practicable. Where an Employer elects not to fill the vacancy, or to make changes to the vacant position, they must review any obligations under <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation).</p><p><strong>76.3</strong> During any period between a position becoming vacant and the position being filled, the Employer will ensure Employees’ workloads are managed in accordance with <a href="/eba/ebas/biomedical-engineers/classification-staffing/84-workload.html">clause 84</a> (Workload). This may include but is not limited to:</p><p><strong>(a)</strong> Backfilling the vacant position;</p><p><strong>(b)</strong> Prioritising work in the area the vacancy has occurred to ensure the work that was done by the Employee who has left is not required to be undertaken by any other staff member/s; or</p><p><strong>(c)</strong> Prioritising work in the area the vacancy has arisen to ensure workloads of staff member/s who may be asked to perform the priority duties of the vacant position are adjusted by reducing their normal duties.</p><p>77 Replacement Positions (The Royal Children’s and The Royal Women’s Hospital Only)</p><p><strong>77.1</strong> The Employer shall discuss with affected Employees strategies to address workload issues arising from where an incumbent Employee is absent on prolonged leave, such as extended annual leave, parental leave, long service leave and WorkCover.</p><p><strong>77.2</strong> Such discussions shall occur in consultation with the relevant Department Head and any nominated representative chosen by the Employee (which may be the Union) and shall have regard to the operational requirements of the particular workplace.</p><p>PRACTICE EMPLOYMENT COMMITMENT</p>',11)])])}const u=a(s,[["render",i]]);export{m as __pageData,u as default};
